.tb-3d-container {
    width: 100%;
    height: 100%;
    background: #020b12;
    overflow: hidden;
}
.tb-3d-info {
    position: absolute;
    bottom: 8px;
    left: 50%;
    transform: translateX(-50%);
    color: rgba(0,217,255,0.3);
    font-size: 10px;
    font-family: 'Segoe UI','Microsoft YaHei',sans-serif;
    pointer-events: none;
    z-index: 10;
}

descriptor.controllerScript:
/**
 * 智慧农业大棚 - 3D 模型视图 Widget
 * 适配 ThingsBoard CE 4.3.0.1
 * Three.js 从本地静态服务器加载 (port 9000)
 */

// ========== 配置 ==========
const THREE_BASE = 'http://192.168.161.1:9000';

// ========== 状态变量 ==========
let threeReady = false;
let sceneData = {
    fanStatus: false,
    lampStatus: false,
    sprayStatus: false,
    pumpStatus: false,
    soilAlarm: false,
    waterAlarm: false
};
let threeObjects = {};
let renderer, scene, camera, controls;
let THREE;  // 模块引用
let animFrameId = null;
let containerEl = null;

// ========== 加载 Three.js (importmap + dynamic import) ==========
function loadThreeModule() {
    // 先插入 importmap，映射 'three' 到本地服务器
    var map = document.createElement('script');
    map.type = 'importmap';
    map.textContent = JSON.stringify({
        imports: {
            'three': THREE_BASE + '/three.module.js',
            'three/addons/': THREE_BASE + '/'
        }
    });
    document.head.appendChild(map);

    // 动态导入
    return import('three').then(function(m) {
        THREE = m;
        return import('three/addons/OrbitControls.js');
    }).then(function() {
        console.log('[3D Widget] Three.js loaded from local server');
        initThree();
    }).catch(function(err) {
        console.error('[3D Widget] Failed to load Three.js:', err);
        var el = document.getElementById('tb-3d-canvas');
        if (el) el.innerHTML = '<div style=\"color:#ff3860;padding:40px;text-align:center\">3D 模型加载失败<br><small>请检查静态文件服务器</small></div>';
    });
}

function initThree() {
    containerEl = document.getElementById('tb-3d-canvas');
    if (!containerEl || !THREE) return;

    // 场景
    scene = new THREE.Scene();
    scene.background = new THREE.Color('#020b12');

    // 相机
    camera = new THREE.PerspectiveCamera(45, containerEl.clientWidth / Math.max(containerEl.clientHeight, 1), 0.1, 100);
    camera.position.set(6, 5, 9);

    // 渲染器
    renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setSize(containerEl.clientWidth, containerEl.clientHeight);
    renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
    renderer.shadowMap.enabled = true;
    containerEl.appendChild(renderer.domElement);

    // OrbitControls
    controls = new THREE.OrbitControls(camera, renderer.domElement);
    controls.enableDamping = true;
    controls.dampingFactor = 0.08;
    controls.target.set(0, 1.2, 0);
    controls.minDistance = 3;
    controls.maxDistance = 18;
    controls.maxPolarAngle = Math.PI * 0.55;
    controls.update();

    // 光照
    scene.add(new THREE.AmbientLight('#1a3050', 1.2));
    var dirLight = new THREE.DirectionalLight('#e8f0ff', 1.8);
    dirLight.position.set(5, 8, 3);
    dirLight.castShadow = true;
    dirLight.shadow.mapSize.set(512, 512);
    dirLight.shadow.camera.near = 0.5;
    dirLight.shadow.camera.far = 30;
    dirLight.shadow.camera.left = -10;
    dirLight.shadow.camera.right = 10;
    dirLight.shadow.camera.top = 10;
    dirLight.shadow.camera.bottom = -10;
    scene.add(dirLight);

    // 地面
    var ground = new THREE.Mesh(
        new THREE.PlaneGeometry(14, 10),
        new THREE.MeshStandardMaterial({ color: '#1a3020', roughness: 0.9 })
    );
    ground.rotation.x = -Math.PI / 2;
    ground.receiveShadow = true;
    scene.add(ground);
    var grid = new THREE.PolarGridHelper(7, 32, 20, 64, '#0a2a30', '#0a2a30');
    grid.position.y = 0.01;
    scene.add(grid);

    // 大棚骨架
    var poleMat = new THREE.MeshStandardMaterial({ color: '#8098a8', roughness: 0.4, metalness: 0.6 });
    var building = new THREE.Group();
    [[-3,1.5,-2],[3,1.5,-2],[-3,1.5,2],[3,1.5,2]].forEach(function(p) {
        var pole = new THREE.Mesh(new THREE.CylinderGeometry(0.08,0.08,3,8), poleMat);
        pole.position.set(p[0],p[1],p[2]); pole.castShadow = true;
        building.add(pole);
    });
    [-2,2].forEach(function(z) {
        var b = new THREE.Mesh(new THREE.CylinderGeometry(0.05,0.05,6,8), poleMat);
        b.rotation.z=Math.PI/2; b.position.set(0,3,z); b.castShadow=true; building.add(b);
    });
    [-3,3].forEach(function(x) {
        var c = new THREE.Mesh(new THREE.CylinderGeometry(0.05,0.05,4,8), poleMat);
        c.rotation.x=Math.PI/2; c.position.set(x,3,0); c.castShadow=true; building.add(c);
    });
    var roof = new THREE.Mesh(
        new THREE.CylinderGeometry(2.5,2.7,6,16,1,false,0,Math.PI),
        new THREE.MeshStandardMaterial({color:'#c8e8ff',roughness:0.2,metalness:0.1,transparent:true,opacity:0.25,side:THREE.DoubleSide})
    );
    roof.rotation.set(0,0,Math.PI/2); roof.position.set(0,3,0); roof.receiveShadow=true;
    building.add(roof);
    scene.add(building);

    // 作物区
    scene.add((function() {
        var c = new THREE.Mesh(new THREE.PlaneGeometry(4.5,3), new THREE.MeshStandardMaterial({color:'#2d5a20',roughness:0.8}));
        c.rotation.x=-Math.PI/2; c.position.y=0.02; c.receiveShadow=true; return c;
    })());

    // 土壤
    var soil = new THREE.Mesh(new THREE.PlaneGeometry(5,3.4), new THREE.MeshStandardMaterial({color:'#4a3020',roughness:0.95}));
    soil.rotation.x=-Math.PI/2; soil.position.y=0.01; soil.receiveShadow=true;
    threeObjects.soil = soil; scene.add(soil);

    // 风扇 x4
    threeObjects.fans = [];
    [-1.5,1.5].forEach(function(x) {
        [-1.8,1.8].forEach(function(z) {
            var fg = new THREE.Group();
            fg.add((function(){var h=new THREE.Mesh(new THREE.CylinderGeometry(0.3,0.35,0.15,16),new THREE.MeshStandardMaterial({color:'#506070',roughness:0.3,metalness:0.5}));h.castShadow=true;return h;})());
            var blades = new THREE.Group();
            for (var i=0;i<3;i++) {var bl=new THREE.Mesh(new THREE.BoxGeometry(0.08,0.5,0.06),new THREE.MeshStandardMaterial({color:'#8098a8',roughness:0.3,metalness:0.4}));bl.rotation.z=i/3*Math.PI*2;bl.castShadow=true;blades.add(bl);}
            blades.position.y=0.05; fg.add(blades); fg.userData={blades:blades};
            var br=new THREE.Mesh(new THREE.CylinderGeometry(0.04,0.04,0.5,8),poleMat);br.position.y=-0.3;br.castShadow=true;fg.add(br);
            fg.position.set(x,2.2,z); scene.add(fg); threeObjects.fans.push(fg);
        });
    });

    // 补光灯 x4
    threeObjects.lamps = [];
    [-1.2,1.2].forEach(function(x) {
        [-1.2,1.2].forEach(function(z) {
            var lg = new THREE.Group();
            lg.add(new THREE.Mesh(new THREE.BoxGeometry(0.5,0.08,0.12),new THREE.MeshStandardMaterial({color:'#888',roughness:0.3,metalness:0.5})));
            var gp = new THREE.Mesh(new THREE.PlaneGeometry(0.4,0.06),new THREE.MeshBasicMaterial({color:'#ffe8a0',side:THREE.DoubleSide,transparent:true,opacity:0}));
            gp.rotation.x=-Math.PI/2; gp.position.y=-0.05; lg.add(gp);
            var pl = new THREE.PointLight('#ffe8a0',0,3); pl.position.y=-0.3; lg.add(pl);
            lg.userData={glow:gp,light:pl}; lg.position.set(x,2.8,z);
            scene.add(lg); threeObjects.lamps.push(lg);
        });
    });

    // 喷淋粒子
    threeObjects.sprayGroup = new THREE.Group(); threeObjects.sprayGroup.visible = false;
    for (var i=0;i<80;i++) {
        var pt=new THREE.Mesh(new THREE.SphereGeometry(0.03,4,3),new THREE.MeshBasicMaterial({color:'#88ddff',transparent:true,opacity:0.7}));
        pt.position.set(-2+Math.random()*4,1.5+Math.random(),-1+Math.random()*2);
        pt.userData={baseY:pt.position.y,speed:0.5+Math.random()*2,offset:Math.random()*Math.PI*2};
        threeObjects.sprayGroup.add(pt);
    }
    scene.add(threeObjects.sprayGroup);

    // 水箱
    threeObjects.tank = new THREE.Mesh(new THREE.CylinderGeometry(0.4,0.45,1.2,16),new THREE.MeshStandardMaterial({color:'#4060a0',roughness:0.3,metalness:0.6}));
    threeObjects.tank.position.set(3.5,0.6,2); threeObjects.tank.castShadow=threeObjects.tank.receiveShadow=true;
    scene.add(threeObjects.tank);

    // 管道
    threeObjects.pipe = new THREE.Mesh(new THREE.CylinderGeometry(0.06,0.06,3,8),new THREE.MeshStandardMaterial({color:'#5070a0',roughness:0.3,metalness:0.5}));
    threeObjects.pipe.rotation.z=Math.PI/2; threeObjects.pipe.position.set(1.5,0.3,2);
    scene.add(threeObjects.pipe);

    threeReady = true;
    console.log('[3D Widget] Scene ready');

    // 渲染循环
    var clock = new THREE.Clock();
    function render() {
        animFrameId = requestAnimationFrame(render);
        var dt = Math.min(clock.getDelta(), 0.1);
        var time = performance.now() * 0.001;
        if (controls) controls.update();

        if (threeObjects.fans && sceneData.fanStatus) {
            threeObjects.fans.forEach(function(f) {
                if (f.userData.blades) f.userData.blades.rotation.y += dt * 12;
            });
        }
        if (threeObjects.lamps) {
            threeObjects.lamps.forEach(function(l) {
                if (l.userData.glow) l.userData.glow.material.opacity += ((sceneData.lampStatus?0.85:0)-l.userData.glow.material.opacity)*Math.min(dt*4,1);
                if (l.userData.light) l.userData.light.intensity += ((sceneData.lampStatus?2.5:0)-l.userData.light.intensity)*Math.min(dt*4,1);
            });
        }
        if (threeObjects.sprayGroup) {
            threeObjects.sprayGroup.visible = sceneData.sprayStatus;
            if (sceneData.sprayStatus) {
                threeObjects.sprayGroup.children.forEach(function(p) {
                    p.position.y = p.userData.baseY + Math.sin(time*p.userData.speed+p.userData.offset)*0.3;
                    p.material.opacity = 0.3 + Math.abs(Math.cos(time*p.userData.speed+p.userData.offset))*0.5;
                });
            }
        }
        if (threeObjects.pipe) {
            threeObjects.pipe.material.color.set(sceneData.pumpStatus?'#00d9ff':'#5070a0');
            threeObjects.pipe.material.emissive = sceneData.pumpStatus ? new THREE.Color('#003040') : new THREE.Color('#000000');
            threeObjects.pipe.material.emissiveIntensity = sceneData.pumpStatus?0.5:0;
        }
        if (threeObjects.soil) threeObjects.soil.material.color.set(sceneData.soilAlarm?'#8a5030':'#4a3020');
        if (threeObjects.tank) threeObjects.tank.material.color.set(sceneData.waterAlarm?'#a03030':'#4060a0');

        if (renderer && scene && camera) renderer.render(scene, camera);
    }
    render();
}

// ========== 读取遥测 ==========
function getLatestValue(ctx, key, defaultValue) {
    if (!ctx || !ctx.data) return defaultValue;
    for (var i = 0; i < ctx.data.length; i++) {
        var item = ctx.data[i];
        if (item.dataKey && item.dataKey.name === key && item.data && item.data.length > 0) {
            var last = item.data[item.data.length - 1];
            return last.length > 1 ? last[1] : defaultValue;
        }
    }
    return defaultValue;
}

// ========== TB Widget 生命周期 ==========
self.onInit = function() {
    console.log('[3D Widget] Init, loading Three.js from ' + THREE_BASE);
    loadThreeModule();
};

self.onDataUpdated = function() {
    if (!threeReady) return;
    sceneData.fanStatus = getLatestValue(self.ctx, 'fanStatus', false) === true || getLatestValue(self.ctx, 'fanStatus', false) === 'true';
    sceneData.lampStatus = getLatestValue(self.ctx, 'lampStatus', false) === true || getLatestValue(self.ctx, 'lampStatus', false) === 'true';
    sceneData.sprayStatus = getLatestValue(self.ctx, 'sprayStatus', false) === true || getLatestValue(self.ctx, 'sprayStatus', false) === 'true';
    sceneData.pumpStatus = getLatestValue(self.ctx, 'pumpStatus', false) === true || getLatestValue(self.ctx, 'pumpStatus', false) === 'true';
    sceneData.soilAlarm = getLatestValue(self.ctx, 'soilAlarm', false) === true || getLatestValue(self.ctx, 'soilAlarm', false) === 'true';
    sceneData.waterAlarm = getLatestValue(self.ctx, 'waterAlarm', false) === true || getLatestValue(self.ctx, 'waterAlarm', false) === 'true';
};

self.onResize = function() {
    if (!threeReady || !renderer || !camera || !containerEl) return;
    camera.aspect = containerEl.clientWidth / Math.max(containerEl.clientHeight, 1);
    camera.updateProjectionMatrix();
    renderer.setSize(containerEl.clientWidth, containerEl.clientHeight);
};

self.onDestroy = function() {
    if (animFrameId) { cancelAnimationFrame(animFrameId); animFrameId = null; }
    if (renderer) {
        renderer.dispose();
        if (containerEl && renderer.domElement) containerEl.removeChild(renderer.domElement);
        renderer = null;
    }
    if (scene) {
        scene.traverse(function(obj) {
            if (obj.geometry) obj.geometry.dispose();
            if (obj.material) {
                if (Array.isArray(obj.material)) obj.material.forEach(function(m){m.dispose();});
                else obj.material.dispose();
            }
        });
        scene = null;
    }
    threeReady = false;
    console.log('[3D Widget] Destroyed');
};
